select 
from `stock_bar_agg`
where `code` = #{code} and `period_type` = #{periodType}

    and `bar_date` >= #{fromInclusive}


    and `bar_date` <= #{toInclusive}

order by `bar_date` asc

select 
from `stock_bar_agg`
where `code` = #{code} and `period_type` = #{periodType}

    and `bar_date` <= #{toInclusive}

order by `bar_date` desc
limit #{limit}

select 
from `stock_bar_agg`
where `code` = #{code} and `period_type` = #{periodType}
and `bar_date` < #{beforeExclusive}
order by `bar_date` desc
limit #{limit}
